#include<bits/stdc++.h>
using namespace std;
int a[10000010],lson[10000010],rson[10000010];
int stk[10000010],n;
int main()
{
    scanf("%d",&n);
    for(int i=1;i<=n;i++)
    {
        scanf("%d",&a[i]);
    }
    int top=0;
    for(int i=1;i<=n;i++)
    {
        int k=top;
        while(k>0&&a[stk[k]]>a[i])
        {
            k--;
        }
        if(k)
        {
            rson[stk[k]]=i;
        }
        if(k<top)
        {
            lson[i]=stk[k+1];
        }
        stk[++k]=i;
        top=k;
    }
    long long ans1=0,ans2=0;
    for(int i=1;i<=n;i++)
    {
        ans1^=1ll*i*(lson[i]+1);
        ans2^=1ll*i*(rson[i]+1);
    }
    printf("%lld %lld",ans1,ans2);
    return 0;
}
